export function parseArgs(argv) {
  const result = { _: [] }
  let index = 0
  while (index < argv.length) {
    const arg = argv[index]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      index += 1
      continue
    }
    const key = arg.slice(2)
    if (arg === `--${key}`) {
      result[key] = true
      index += 1
      continue
    }
    if (arg.includes('=')) {
      const [k, v] = arg.split('=', 2)
      result[k] = v
      index += 1
      continue
    }
    result[key] = argv[++index]
    index += 1
  }
  return result
}

